from dataclasses import dataclass, field
from datetime import date
from typing import Optional

@dataclass
class BenefitActual:
    metric_id: str
    measurement_date: date
    actual_value: float
    baseline_value: float
    target_value: float
    measurement_notes: str = ""     # any data quality caveats
    confounds_active: list[str] = field(default_factory=list)  # confound IDs active this period

    @property
    def delta_vs_baseline(self) -> float:
        return self.actual_value - self.baseline_value

    @property
    def delta_pct(self) -> float:
        if self.baseline_value == 0:
            return float("inf")
        return self.delta_vs_baseline / self.baseline_value * 100

    @property
    def progress_to_target_pct(self) -> float:
        """
        How much of the gap from baseline to target has been closed?
        Returns > 100 if the target has been exceeded.
        """
        gap = self.target_value - self.baseline_value
        if gap == 0:
            return 100.0
        return (self.actual_value - self.baseline_value) / gap * 100

    def rag(self) -> str:
        p = self.progress_to_target_pct
        if p >= 90:
            return "GREEN"
        if p >= 60:
            return "AMBER"
        return "RED"

    def summary(self) -> str:
        return (
            f"{self.metric_id} @ {self.measurement_date}: "
            f"{self.actual_value:.1f} (baseline {self.baseline_value:.1f}, "
            f"target {self.target_value:.1f}) | "
            f"Δ={self.delta_pct:+.0f}% | "
            f"progress={self.progress_to_target_pct:.0f}% | {self.rag()}"
        )


@dataclass
class BenefitsRegister:
    programme: str
    actuals: list[BenefitActual] = field(default_factory=list)

    def add(self, actual: BenefitActual) -> None:
        self.actuals.append(actual)

    def latest_for(self, metric_id: str) -> Optional[BenefitActual]:
        matches = [a for a in self.actuals if a.metric_id == metric_id]
        return max(matches, key=lambda a: a.measurement_date) if matches else None

    def portfolio_rag(self) -> dict[str, int]:
        """Count of GREEN / AMBER / RED across all latest metrics."""
        from collections import Counter
        counter: Counter = Counter()
        seen: set[str] = set()
        for a in sorted(self.actuals, key=lambda x: x.measurement_date, reverse=True):
            if a.metric_id not in seen:
                counter[a.rag()] += 1
                seen.add(a.metric_id)
        return dict(counter)

from datetime import date, timedelta
from enum import Enum

class TrackingCadence(Enum):
    WEEKLY     = 7
    BIWEEKLY   = 14
    MONTHLY    = 30
    QUARTERLY  = 91

def next_measurement_date(last_date: date, launch_date: date) -> tuple[date, TrackingCadence]:
    """Return the next measurement date and cadence based on weeks since launch."""
    weeks_since_launch = (last_date - launch_date).days // 7
    if weeks_since_launch < 5:
        cadence = TrackingCadence.WEEKLY
    elif weeks_since_launch < 13:
        cadence = TrackingCadence.BIWEEKLY
    elif weeks_since_launch < 25:
        cadence = TrackingCadence.MONTHLY
    else:
        cadence = TrackingCadence.QUARTERLY
    return last_date + timedelta(days=cadence.value), cadence


def should_alert(actual: BenefitActual, weeks_since_launch: int) -> bool:
    """
    Alert if progress is below expected trajectory at key checkpoints.
    Expected: 30% of target by W+4, 60% by W+8, 80% by W+12, 100% by W+16.
    """
    checkpoints = {4: 30, 8: 60, 12: 80, 16: 100}
    for week, expected_pct in checkpoints.items():
        if weeks_since_launch == week:
            return actual.progress_to_target_pct < expected_pct
    return False

from dataclasses import dataclass
from typing import Optional

@dataclass
class ABTestResult:
    metric_id: str
    treatment_group_mean: float
    control_group_mean: float
    treatment_sample_n: int
    control_sample_n: int
    p_value: float
    confidence_interval_95: tuple[float, float]  # (low, high) of effect

    @property
    def effect_size(self) -> float:
        """Absolute difference (treatment − control)."""
        return self.treatment_group_mean - self.control_group_mean

    @property
    def is_significant(self) -> bool:
        return self.p_value < 0.05

    def attribution_statement(self) -> str:
        if not self.is_significant:
            return (
                f"No statistically significant GenAI effect detected for {self.metric_id} "
                f"(p={self.p_value:.3f}). Cannot claim attribution."
            )
        lo, hi = self.confidence_interval_95
        return (
            f"GenAI caused a {self.effect_size:+.1f} change in {self.metric_id} "
            f"(95% CI: [{lo:.1f}, {hi:.1f}], p={self.p_value:.3f}). "
            f"Statistically significant."
        )


@dataclass
class ExpertDecomposition:
    metric_id: str
    total_delta: float             # baseline − actual (observed)
    attributions: dict[str, float] # {"GenAI": 1.5, "Process redesign": 0.6, ...}
    rationale: dict[str, str]      # per-source rationale
    signed_by: list[str]           # who agreed

    def validate(self) -> list[str]:
        errors = []
        total = sum(self.attributions.values())
        if abs(total - self.total_delta) > 0.01:
            errors.append(
                f"Attribution sum ({total:.2f}) does not match total delta ({self.total_delta:.2f})"
            )
        if len(self.signed_by) < 2:
            errors.append("Expert decomposition requires sign-off from at least 2 parties")
        return errors

    def genai_share_pct(self) -> float:
        genai = self.attributions.get("GenAI", 0.0)
        return genai / self.total_delta * 100 if self.total_delta else 0.0

@dataclass
class NetBenefitCalculation:
    programme: str
    gross_benefit_annual_gbp: float
    genai_attribution_pct: float       # from expert decomposition or A/B test
    inference_cost_annual_gbp: float
    maintenance_cost_annual_gbp: float
    support_cost_annual_gbp: float

    @property
    def attributed_gross_benefit(self) -> float:
        return self.gross_benefit_annual_gbp * (self.genai_attribution_pct / 100)

    @property
    def total_annual_cost(self) -> float:
        return (self.inference_cost_annual_gbp +
                self.maintenance_cost_annual_gbp +
                self.support_cost_annual_gbp)

    @property
    def net_annual_benefit(self) -> float:
        return self.attributed_gross_benefit - self.total_annual_cost

    @property
    def benefit_cost_ratio(self) -> float:
        return self.attributed_gross_benefit / self.total_annual_cost if self.total_annual_cost else float("inf")

    def summary(self) -> str:
        return (
            f"Gross benefit: £{self.gross_benefit_annual_gbp:,.0f}  "
            f"GenAI attribution: {self.genai_attribution_pct:.0f}%  "
            f"Attributed: £{self.attributed_gross_benefit:,.0f}  "
            f"Annual cost: £{self.total_annual_cost:,.0f}  "
            f"Net: £{self.net_annual_benefit:,.0f}  "
            f"BCR: {self.benefit_cost_ratio:.1f}x"
        )


# Example
calc = NetBenefitCalculation(
    programme="genai-customer-support",
    gross_benefit_annual_gbp=850_000,
    genai_attribution_pct=65,
    inference_cost_annual_gbp=72_000,
    maintenance_cost_annual_gbp=35_000,
    support_cost_annual_gbp=18_000,
)
print(calc.summary())
# Gross benefit: £850,000  GenAI attribution: 65%  Attributed: £552,500
# Annual cost: £125,000  Net: £427,500  BCR: 4.4x

from dataclasses import dataclass
from datetime import date
from enum import Enum

class RebaselineReason(Enum):
    EXTERNAL_CHANGE  = "external_change"
    SCOPE_EXPANSION  = "scope_expansion"
    DATA_QUALITY_FIX = "data_quality_fix"

@dataclass
class BaselineAmendment:
    metric_id: str
    original_baseline: float
    revised_baseline: float
    reason: RebaselineReason
    rationale: str
    amendment_date: date
    authorised_by: list[str]   # must include original signatories

    @property
    def delta_pct(self) -> float:
        if self.original_baseline == 0:
            return 0.0
        return (self.revised_baseline - self.original_baseline) / self.original_baseline * 100

    def validate(self) -> list[str]:
        errors = []
        if abs(self.delta_pct) < 5:
            errors.append(
                f"Amendment is only {self.delta_pct:.1f}% — below the 5% materiality threshold; "
                "consider whether re-baselining is warranted"
            )
        if len(self.authorised_by) < 2:
            errors.append("Re-baseline requires authorisation from at least 2 parties")
        return errors
